SELECT COUNT(*) 
FROM competition_participants 
WHERE competition_id = 1 AND status = 'active';

SELECT MAX(cumulative_score) AS highest_cumulative_score
FROM (
    SELECT user_id, SUM(score) AS cumulative_score
    FROM submissions
    GROUP BY user_id
) AS user_scores;

SELECT username
FROM users
WHERE user_id = 0;
